import base64
import binascii
import io
import pickle
from typing import Any


class _SafeUnpickler(pickle.Unpickler):
    """
    Restricted unpickler that only allows a minimal set of harmless built-in
    container/value types needed for simple preference dictionaries.
    """

    _ALLOWED_BUILTINS = {
        "dict",
        "list",
        "tuple",
        "set",
        "frozenset",
        "str",
        "bytes",
        "int",
        "float",
        "bool",
        "complex",
        "NoneType",
    }

    def find_class(self, module: str, name: str) -> Any:
        if module == "builtins" and name in self._ALLOWED_BUILTINS:
            return getattr(__import__(module), name)
        raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Safely load user preferences from a base64-encoded cookie string.

    Returns an empty dictionary for invalid, malformed, unsafe, or unexpected
    input.
    """
    if not encoded_prefs or not isinstance(encoded_prefs, str):
        return {}

    try:
        raw_data = base64.b64decode(encoded_prefs, validate=True)
    except (binascii.Error, ValueError):
        return {}

    try:
        prefs = _SafeUnpickler(io.BytesIO(raw_data)).load()
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError, AttributeError):
        return {}

    if isinstance(prefs, dict):
        return prefs

    return {}

