import base64
import binascii
import io
import json
import pickle


class _SafeUnpickler(pickle.Unpickler):
    """
    Restricted unpickler that only allows basic built-in container/value types.
    """

    _ALLOWED_BUILTINS = {
        "builtins": {
            "dict",
            "list",
            "tuple",
            "set",
            "frozenset",
            "str",
            "int",
            "float",
            "bool",
            "bytes",
            "bytearray",
            "complex",
            "NoneType",
        }
    }

    def find_class(self, module, name):
        if module in self._ALLOWED_BUILTINS and name in self._ALLOWED_BUILTINS[module]:
            return getattr(__import__(module, fromlist=[name]), name)
        raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")


def _safe_pickle_loads(data: bytes):
    return _SafeUnpickler(io.BytesIO(data)).load()


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Supports:
    - Base64-encoded JSON objects
    - Legacy Base64-encoded pickle data, deserialized with a restricted unpickler

    Invalid, malformed, or unexpected input results in an empty dictionary.
    """
    if not encoded_prefs:
        return {}

    try:
        decoded_data = base64.b64decode(encoded_prefs, validate=True)
    except (ValueError, TypeError, binascii.Error):
        return {}

    try:
        preferences = json.loads(decoded_data.decode("utf-8"))
        if isinstance(preferences, dict):
            return preferences
    except (UnicodeDecodeError, json.JSONDecodeError, ValueError, TypeError):
        pass

    try:
        preferences = _safe_pickle_loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError, AttributeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

