def _safe_unpickle(data: bytes) -> Any:
    """Safely unpickle only simple builtin container data."""
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Decode and restore user preferences from a Base64-encoded cookie string.

    Supported payloads:
    - Base64-encoded JSON representing a dictionary.
    - Base64-encoded pickle representing a dictionary of simple values.

    Args:
