    Supports safe base64-encoded JSON and restricted pickle payloads for
    backwards compatibility. Returns an empty dictionary for invalid input.
    """
    if not encoded_prefs:
        return {}

    try:
        decoded_data = base64.b64decode(encoded_prefs, validate=True)
    except (binascii.Error, ValueError, TypeError):
        return {}

    try:
        preferences = json.loads(decoded_data.decode("utf-8"))
        if isinstance(preferences, dict):
            return preferences
        return {}
    except (UnicodeDecodeError, json.JSONDecodeError, ValueError, TypeError):
        pass

    try:
        preferences = _safe_pickle_loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError, AttributeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

