from typing import Any


class _SafeUnpickler(pickle.Unpickler):
    """
    Restricted unpickler that only allows a minimal set of safe built-in types.
    This prevents execution of arbitrary code during deserialization.
    """

    _ALLOWED_BUILTINS = {
        "builtins": {
            "dict",
            "list",
            "tuple",
            "set",
            "frozenset",
            "str",
            "int",
            "float",
            "bool",
            "bytes",
            "NoneType",
        }
    }

    def find_class(self, module: str, name: str) -> Any:
        if module in self._ALLOWED_BUILTINS and name in self._ALLOWED_BUILTINS[module]:
            import builtins
            return getattr(builtins, name)
        raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")


def _safe_pickle_loads(data: bytes) -> Any:
    return _SafeUnpickler(io.BytesIO(data)).load()


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Supports base64-encoded JSON objects and legacy base64-encoded pickled
    dictionaries, while using a restricted unpickler for safety.

    Args:
        encoded_prefs: A base64-encoded string containing user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns an empty dictionary for missing, invalid, or non-dictionary data.
    """
    if not encoded_prefs:
        return {}

    try:
        decoded_data = base64.b64decode(encoded_prefs, validate=True)
    except ValueError:
        return {}

    try:
        decoded_text = decoded_data.decode("utf-8")
        preferences = json.loads(decoded_text)
        if isinstance(preferences, dict):
            return preferences
    except (UnicodeDecodeError, json.JSONDecodeError):
        pass

    try:
        preferences = _safe_pickle_loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError, AttributeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

